import{_ as i,o as s,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Numerisation de recus","description":"","frontmatter":{},"headers":[],"relativePath":"fr/advanced/receipt-scanning.md","filePath":"fr/advanced/receipt-scanning.md"}'),l={name:"fr/advanced/receipt-scanning.md"};function t(n,e,o,u,c,d){return s(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="numerisation-de-recus" tabindex="-1">Numerisation de recus <a class="header-anchor" href="#numerisation-de-recus" aria-label="Permalink to &quot;Numerisation de recus&quot;">​</a></h1><p>Extrayez automatiquement les donnees de depenses a partir d&#39;images de recus et de factures PDF grace a l&#39;OCR alimente par l&#39;IA.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La numerisation de recus necessite le plan <strong>Pro</strong> ou superieur.</p></div><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Au lieu de saisir manuellement chaque depense, prenez une photo d&#39;un recu ou telechargez un PDF et laissez MyCompanyDesk extraire automatiquement les details.</p><h2 id="formats-pris-en-charge" tabindex="-1">Formats pris en charge <a class="header-anchor" href="#formats-pris-en-charge" aria-label="Permalink to &quot;Formats pris en charge&quot;">​</a></h2><ul><li><strong>Images</strong> -- JPEG, PNG, WebP</li><li><strong>PDF</strong> -- Factures et recus PDF</li><li><strong>Taille maximale de fichier</strong> -- 50 Mo</li></ul><h2 id="comment-numeriser-un-recu" tabindex="-1">Comment numeriser un recu <a class="header-anchor" href="#comment-numeriser-un-recu" aria-label="Permalink to &quot;Comment numeriser un recu&quot;">​</a></h2><ol><li>Allez dans <strong>Depenses &gt; Numeriser un recu</strong></li><li>Telechargez votre fichier de recu (glisser-deposer ou cliquez pour parcourir)</li><li>Choisissez le mode d&#39;extraction : <ul><li><strong>Simple</strong> -- Extraire une depense du recu</li><li><strong>Multiple</strong> -- Extraire plusieurs lignes du meme recu</li></ul></li><li>Attendez le traitement (quelques secondes)</li><li>Verifiez les donnees extraites : <ul><li>Date</li><li>Montant</li><li>Nom du fournisseur</li><li>Description / articles</li></ul></li><li>Modifiez les champs necessitant une correction</li><li>Cliquez sur <strong>Confirmer</strong> pour creer la ou les depenses</li></ol><h2 id="modes-d-extraction" tabindex="-1">Modes d&#39;extraction <a class="header-anchor" href="#modes-d-extraction" aria-label="Permalink to &quot;Modes d&#39;extraction&quot;">​</a></h2><h3 id="mode-simple" tabindex="-1">Mode simple <a class="header-anchor" href="#mode-simple" aria-label="Permalink to &quot;Mode simple&quot;">​</a></h3><p>Ideal pour les recus simples avec un seul total :</p><ul><li>Additions de restaurant</li><li>Recus de station-service</li><li>Achats d&#39;un seul article</li></ul><p>Extrait : date, montant total, fournisseur, description.</p><h3 id="mode-multiple" tabindex="-1">Mode multiple <a class="header-anchor" href="#mode-multiple" aria-label="Permalink to &quot;Mode multiple&quot;">​</a></h3><p>Ideal pour les recus detailles ou les factures :</p><ul><li>Commandes de fournitures de bureau avec plusieurs articles</li><li>Factures fournisseurs avec lignes de detail</li><li>Listes de courses</li></ul><p>Extrait : lignes individuelles avec descriptions et montants.</p><h2 id="parametres-avances" tabindex="-1">Parametres avances <a class="header-anchor" href="#parametres-avances" aria-label="Permalink to &quot;Parametres avances&quot;">​</a></h2><p>Le scanner dispose d&#39;options avancees :</p><ul><li><strong>Instructions personnalisees</strong> -- Ajoutez du contexte pour aider l&#39;IA (par ex., &quot;Ceci est un recu neerlandais d&#39;Albert Heijn&quot;)</li><li><strong>Traitement d&#39;image</strong> -- Amelioration automatique pour les photos de mauvaise qualite</li></ul><h2 id="conseils-pour-de-meilleurs-resultats" tabindex="-1">Conseils pour de meilleurs resultats <a class="header-anchor" href="#conseils-pour-de-meilleurs-resultats" aria-label="Permalink to &quot;Conseils pour de meilleurs resultats&quot;">​</a></h2><ul><li><strong>Bon eclairage</strong> -- Prenez les photos dans de bonnes conditions d&#39;eclairage</li><li><strong>Surface plane</strong> -- Placez le recu sur une surface plane</li><li><strong>Recu complet</strong> -- Assurez-vous que le recu entier est dans le cadre</li><li><strong>Texte lisible</strong> -- Verifiez que le texte est lisible et non flou</li><li><strong>Un recu par scan</strong> -- Numerisez les recus individuellement pour une meilleure precision</li></ul><h2 id="apres-la-numerisation" tabindex="-1">Apres la numerisation <a class="header-anchor" href="#apres-la-numerisation" aria-label="Permalink to &quot;Apres la numerisation&quot;">​</a></h2><p>Une fois confirme, la depense est creee avec :</p><ul><li>Toutes les donnees extraites pre-remplies</li><li>Le recu original joint en piece jointe</li><li>Des suggestions de categorie (si les suggestions IA sont activees)</li></ul><p>Vous pouvez modifier la depense par la suite comme n&#39;importe quelle depense creee manuellement.</p><h2 id="telechargement-par-lot" tabindex="-1">Telechargement par lot <a class="header-anchor" href="#telechargement-par-lot" aria-label="Permalink to &quot;Telechargement par lot&quot;">​</a></h2><p>Telechargez plusieurs recus en une fois :</p><ol><li>Selectionnez plusieurs fichiers</li><li>Chacun est traite independamment</li><li>Verifiez et confirmez chaque extraction</li></ol><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Numerisez les recus des que vous les recevez -- ne les laissez pas s&#39;accumuler</li><li>Verifiez attentivement le montant extrait, surtout pour les recus avec plusieurs devises</li><li>Activez les suggestions IA pour une categorisation automatique apres la numerisation</li><li>Conservez le fichier de recu original en piece jointe a des fins de controle fiscal</li></ul>',32)])])}const h=i(l,[["render",t]]);export{p as __pageData,h as default};
